"""Save Polar Promo Analysis query results Q13a-e to JSON files.

Reads MCP result files (large JSON from Claude tool output) and converts
to standard {tableData, totalData} format for polar_financial_model.py.
"""
import json, os, sys

sys.stdout.reconfigure(encoding='utf-8', errors='replace')

DIR = os.path.dirname(os.path.abspath(__file__))
# Claude tool result files directory
RESULT_DIR = r"C:\Users\user\.claude\projects\c--Users-user-Downloads-ORBITERS-CLAUDE-ORBITERS-CLAUDE\c7c4c7d4-65d8-4677-a3e2-2841f2af9fde\tool-results"


def load_mcp_result(filename):
    """Load an MCP tool result file and extract tableData + totalData."""
    path = os.path.join(RESULT_DIR, filename)
    with open(path, encoding="utf-8") as f:
        raw = json.load(f)
    # MCP results are [{type: "text", text: "...json..."}]
    for item in raw:
        if item.get("type") == "text":
            data = json.loads(item["text"])
            return data.get("tableData", []), data.get("totalData", [])
    return [], []


def save_json(name, table_data, total_data):
    """Save to standard JSON format."""
    obj = {"tableData": table_data, "totalData": total_data}
    path = os.path.join(DIR, name)
    with open(path, "w", encoding="utf-8") as f:
        json.dump(obj, f, ensure_ascii=False)
    print(f"  Saved {name}: {len(table_data)} rows")


print("Saving Q13 Promo Analysis data...")

